"use strict";(self.webpackChunkwiki=self.webpackChunkwiki||[]).push([[4578],{5728:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"linuxwebconsole","metadata":{"permalink":"/wiki/blog/linuxwebconsole","editUrl":"https://github.com/abhilashreddysh/wiki/blob/main/blog/2023-06-26-linuxWebConsole.md","source":"@site/blog/2023-06-26-linuxWebConsole.md","title":"Linux Web Console","description":"Version - 1.0","date":"2023-06-26T00:00:00.000Z","formattedDate":"June 26, 2023","tags":[{"label":"linux","permalink":"/wiki/blog/tags/linux"},{"label":"bash","permalink":"/wiki/blog/tags/bash"},{"label":"php","permalink":"/wiki/blog/tags/php"},{"label":"moniter","permalink":"/wiki/blog/tags/moniter"},{"label":"web","permalink":"/wiki/blog/tags/web"}],"readingTime":0.595,"hasTruncateMarker":true,"authors":[{"name":"Abhilash Reddy","title":"Learning Linux and Automation","url":"https://github.com/abhilashreddysh","email":"abhilashreddysh.99@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/116741403?v=4","key":"abhi"}],"frontMatter":{"slug":"linuxwebconsole","title":"Linux Web Console","description":"Version - 1.0","sidebar_position":3,"tags":["linux","bash","php","moniter","web"],"authors":"abhi"},"nextItem":{"title":"Linux Status Mail","permalink":"/wiki/blog/linuxpythonmail"}},"content":"Web page setup to moniter services and stats of a remote linux machine\\n\\n\x3c!--truncate--\x3e\\n\\n:::info Version - 1.0\\n[Repository Link](https://github.com/abhilashreddysh/AutomationScripts/tree/main/WebConsole)\\n:::\\n\\n### Requirements\\n\\n- Nginx\\n- PHP\\n\\n### Setup\\n\\n- Download the folder and save in nginx `sites-enabled` folder.\\n- Point the default nginx webpage to this folder.\\n- To be able to use the restart feature allow `www-data` user to act as sudo for these commands\\n\\n```config title=\\"/etc/sudoers.d/www-data-access\\"\\n%www-data ALL=NOPASSWD: /bin/systemctl restart nginx\\n%www-data ALL=NOPASSWD: /bin/systemctl restart sshd\\n%www-data ALL=NOPASSWD: /bin/systemctl restart smbd\\n%www-data ALL=NOPASSWD: /bin/systemctl restart transmission-daemon\\n```\\nThis will allow www-data user to be able to use only the above commands as a sudo user.\\n\\nAdd more if there are any other services to be monitered."},{"id":"linuxpythonmail","metadata":{"permalink":"/wiki/blog/linuxpythonmail","editUrl":"https://github.com/abhilashreddysh/wiki/blob/main/blog/2023-05-25-linuxStatusMail.md","source":"@site/blog/2023-05-25-linuxStatusMail.md","title":"Linux Status Mail","description":"Version - 1.3","date":"2023-05-25T00:00:00.000Z","formattedDate":"May 25, 2023","tags":[{"label":"linux","permalink":"/wiki/blog/tags/linux"},{"label":"python","permalink":"/wiki/blog/tags/python"},{"label":"mail","permalink":"/wiki/blog/tags/mail"},{"label":"moniter","permalink":"/wiki/blog/tags/moniter"}],"readingTime":0.485,"hasTruncateMarker":true,"authors":[{"name":"Abhilash Reddy","title":"Learning Linux and Automation","url":"https://github.com/abhilashreddysh","email":"abhilashreddysh.99@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/116741403?v=4","key":"abhi"}],"frontMatter":{"slug":"linuxpythonmail","title":"Linux Status Mail","description":"Version - 1.3","sidebar_position":2,"tags":["linux","python","mail","moniter"],"authors":"abhi"},"prevItem":{"title":"Linux Web Console","permalink":"/wiki/blog/linuxwebconsole"},"nextItem":{"title":"peelSoN","permalink":"/wiki/blog/peelson"}},"content":"Python Script to get linux services update through mail. Can be automated and scheduled to run in time intervals using crontab.\\n\\n\x3c!--truncate--\x3e\\n\\n:::info Version - 1.3\\n[Repository Link](https://github.com/abhilashreddysh/AutomationScripts/tree/main/LinuxStatusMail)\\n:::\\n\\n### Setup\\n\\nYou can use the `generateConfig.py` to generate a config file by providing the required inputs for the first time and later update the generated config file accordingly.\\n\\nTo do it manually create the below file in the project root dir\\n\\n```config title=\\"config.py -- (Generated from generateconfig.py)\\"\\ngmailUser = <Sender Email>\\ngmailPassword = <Password>\\nrecipient = <Recipients Mail>\\nservices_to_be_monitered = <List of Services to be monitered>\\n```"},{"id":"peelson","metadata":{"permalink":"/wiki/blog/peelson","editUrl":"https://github.com/abhilashreddysh/wiki/blob/main/blog/2023-05-24-peelson.md","source":"@site/blog/2023-05-24-peelson.md","title":"peelSoN","description":"Version - 3.0","date":"2023-05-24T00:00:00.000Z","formattedDate":"May 24, 2023","tags":[{"label":"peelson","permalink":"/wiki/blog/tags/peelson"},{"label":"powershell","permalink":"/wiki/blog/tags/powershell"},{"label":"windows","permalink":"/wiki/blog/tags/windows"}],"readingTime":1.71,"hasTruncateMarker":true,"authors":[{"name":"Abhilash Reddy","title":"Learning Linux and Automation","url":"https://github.com/abhilashreddysh","email":"abhilashreddysh.99@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/116741403?v=4","key":"abhi"}],"frontMatter":{"slug":"peelson","title":"peelSoN","description":"Version - 3.0","sidebar_position":1,"tags":["peelson","powershell","windows"],"authors":"abhi"},"prevItem":{"title":"Linux Status Mail","permalink":"/wiki/blog/linuxpythonmail"}},"content":"Powershell script to prevent the system from going to sleep.Use this script to keep your computer awake by programmatically pressing the ScrollLock key every X seconds\\n\\n\x3c!--truncate--\x3e\\n\\n:::info Version - 3.0\\n[Repository Link (This repository is private)](https://github.com/abhilashreddysh/peelSoN)\\n\\nVersion - 2.5\\n[Single Script (Public)](https://github.com/abhilashreddysh/AutomationScripts/blob/main/Powershell/peelSoN.ps1)\\n:::\\n\\n## Single script (Public)\\n\\nDownload the script and run in powershell. the script runs in an infinite loop. Click the icon in systemtray and explore more option to see what this script can do.\\n\\n## FAQ (Repository)\\n\\n### How to setup ?\\n\\n#### _(Using Script)_\\n\\nUse initsetup.ps1 to setup and Change the task _peelSoN_ trigger from (AtLogon) --\x3e (On Workstation Unlock) in task scheduler to start the script as soon as you login.\\n\\nOR\\n\\n#### _(Manual Method)_\\n\\nDownload and save this folder with the name \\"peelSoN\\" in C:\\\\temp and run start.vbs script. You can also automate the task by setting up a task in task scheduler to run on every given interval.\\n\\n### How to stop the running session ?\\n\\nEvery time the task is executed, a bat file is created on the desktop as killpeel.bat\\nDouble click this bat file to kill the session and turn off peelSoN.\\n\\n### Where are my logs saved ?\\n\\nLogs are saved at `C:\\\\temp\\\\peelSoN\\\\logs`\\n\\n### How to change my logout time ?\\n\\nEdit the launch.bat file at `C:\\\\temp\\\\peelSoN\\\\` and update the `Hour` and `Min` flag according to your needs.\\n\\n```bat title=\\"C:\\\\temp\\\\peelSoN\\\\launch.bat\\"\\nPowershell.exe -File \\"C:\\\\temp\\\\peelSoN\\\\peelson.ps1\\" -Hour 18 -Min 00 -sleep 120\\n```\\n\\nThe above example stops the script at 18:00 (06:00 PM). **You can also update the sleep timer**.\\n\\n## Changelog\\n\\n:::info \\nVersion 2.x is a single script version which should be manually triggered\\n\\n\\nVersion 3.x is fully automated which include initial setup, auto triggering based on the time set to logoff, and auto updates.\\n:::\\n\\n### 3.0\\n\\n- Script will run anonymously and generate a bat file on desktop to kill it.\\n- Auto install script and setup a task\\n\\n### 2.5\\n\\n- Added Context Menu to run in systemtray\\n\\n### 2.4\\n\\n- Script will now end after the logout time"}]}')}}]);